import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './Dashboard.css';

function Dashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get('/api/dashboard');
        setData(res.data);
      } catch (err) {
        console.error('Error loading dashboard', err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) return <div className="loading">Loading dashboard...</div>;
  if (!data) return <div className="loading">No data available.</div>;

  return (
    <div className="dashboard-page">
      <div className="container">
        <h1>Supplier Dashboard</h1>
        <p className="dashboard-subtitle">Overview of your marketplace activity</p>

        <div className="dashboard-stats">
          <div className="stat-card">
            <h3>{data.stats.products}</h3>
            <p>Products</p>
          </div>
          <div className="stat-card">
            <h3>{data.stats.suppliers}</h3>
            <p>Suppliers</p>
          </div>
          <div className="stat-card">
            <h3>{data.stats.categories}</h3>
            <p>Categories</p>
          </div>
        </div>

        <div className="dashboard-section">
          <div className="section-header">
            <h3>Latest Products</h3>
          </div>
          <div className="latest-products">
            {data.latest_products.map((p) => (
              <div key={p.id} className="latest-card">
                <h4>{p.name}</h4>
                <p>₹{p.price?.toLocaleString() || 'Price on Request'}</p>
                <p className="latest-company">{p.company_name}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
